{
  "name": "Morandi Intelligent Q&A Assistant",
  "description": "A sophisticated AI-powered chat interface featuring a soft Morandi orange color palette, designed for professional advisory and intelligent Q&A tasks.",
  "requestFramePermissions": ["microphone"]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Role {
  USER = 'user',
  MODEL = 'model'
}

export interface Message {
  id: string;
  role: Role;
  content: string;
  timestamp: Date;
  isStreaming?: boolean;
}

export interface ChatSession {
  id: string;
  title: string;
  lastMessage: string;
  category: string;
}

export enum Category {
  FINANCIAL = '财务制度',
  LEGAL = '法务制度',
  BIDDING = '招投标制度',
  MEETING = '会议助手',
  GENERAL = '智能问数'
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { Role } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getGeminiResponse = async (
  history: { role: Role; content: string }[],
  onChunk: (text: string) => void
) => {
  const model = 'gemini-3-flash-preview';

  const contents = history.map(h => ({
    role: h.role,
    parts: [{ text: h.content }]
  }));

  try {
    const chat = ai.chats.create({
      model,
      config: {
        systemInstruction: "你是一个专业的智能中台助手，具备财务、法务、招投标等领域的深度知识。请使用礼貌、清晰且富有洞察力的语言回复用户。你的色调设计理念是莫兰迪橙色系，追求优雅、稳重和高效。请根据用户的需求，提供精准的帮助。",
      }
    });

    // We send the latest message
    const lastUserMessage = history[history.length - 1].content;
    const result = await chat.sendMessageStream({ message: lastUserMessage });

    let fullText = "";
    for await (const chunk of result) {
      const text = chunk.text;
      if (text) {
        fullText += text;
        onChunk(text);
      }
    }
    return fullText;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Sidebar } from './components/Sidebar';
import { Header } from './components/Header';
import { MessageList } from './components/MessageList';
import { MessageInput } from './components/MessageInput';
import { CategoryTabs } from './components/CategoryTabs';
import { Message, Role, Category } from './types';
import { getGeminiResponse } from './services/geminiService';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'welcome',
      role: Role.MODEL,
      content: '您好！我是您的智慧中台助手小优 ✨，随时待机为您排忧解难。目前可以为您解答关于公司法律事务类流程操作指引问题，请问今天有什么可以帮您的吗？',
      timestamp: new Date(),
    }
  ]);
  const [currentCategory, setCurrentCategory] = useState<Category>(Category.GENERAL);
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = useCallback(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [messages, scrollToBottom]);

  const handleSendMessage = async (text: string) => {
    if (!text.trim() || isLoading) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: Role.USER,
      content: text,
      timestamp: new Date(),
    };

    setMessages(prev => [...prev, userMsg]);
    setIsLoading(true);

    const botMsgId = (Date.now() + 1).toString();
    const botMsg: Message = {
      id: botMsgId,
      role: Role.MODEL,
      content: '',
      timestamp: new Date(),
      isStreaming: true,
    };

    setMessages(prev => [...prev, botMsg]);

    try {
      const history = messages.concat(userMsg).map(m => ({
        role: m.role,
        content: m.content
      }));

      let accumulatedResponse = "";
      await getGeminiResponse(history, (chunk) => {
        accumulatedResponse += chunk;
        setMessages(prev => prev.map(m => 
          m.id === botMsgId ? { ...m, content: accumulatedResponse } : m
        ));
      });

      setMessages(prev => prev.map(m => 
        m.id === botMsgId ? { ...m, isStreaming: false } : m
      ));
    } catch (error) {
      setMessages(prev => prev.map(m => 
        m.id === botMsgId ? { ...m, content: '抱歉，我现在遇到了一些问题，请稍后再试。', isStreaming: false } : m
      ));
    } finally {
      setIsLoading(false);
    }
  };

  const handleNewChat = () => {
    setMessages([{
      id: 'welcome',
      role: Role.MODEL,
      content: '您好！我是您的智慧中台助手小优 ✨，开启一段新的对话吧！',
      timestamp: new Date(),
    }]);
  };

  return (
    <div className="flex h-screen w-full bg-[#faf9f6] text-gray-700">
      {/* Sidebar */}
      <Sidebar onNewChat={handleNewChat} currentCategory={currentCategory} />

      {/* Main Content Area */}
      <div className="flex flex-col flex-1 relative overflow-hidden">
        <Header />

        {/* Scrollable Chat Area */}
        <div className="flex-1 overflow-y-auto px-4 sm:px-8 lg:px-12 py-6 space-y-8" ref={scrollRef}>
          {/* Functional Tabs - Similar to Attachment 2 */}
          <div className="flex justify-center mb-8">
            <CategoryTabs active={currentCategory} onSelect={setCurrentCategory} />
          </div>

          <div className="max-w-4xl mx-auto w-full">
             <MessageList messages={messages} />
          </div>
        </div>

        {/* Input Area */}
        <div className="p-4 sm:p-6 bg-transparent">
          <div className="max-w-4xl mx-auto">
            <MessageInput onSend={handleSendMessage} disabled={isLoading} />
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

