import React, { useState, useRef, useEffect } from 'react';

interface MessageInputProps {
  onSend: (text: string) => void;
  disabled?: boolean;
}

export const MessageInput: React.FC<MessageInputProps> = ({ onSend, disabled }) => {
  const [text, setText] = useState('');
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = `${Math.min(textareaRef.current.scrollHeight, 150)}px`;
    }
  }, [text]);

  const handleSubmit = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (text.trim() && !disabled) {
      onSend(text.trim());
      setText('');
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSubmit();
    }
  };

  return (
    <div className="relative group">
      {/* Decorative Microphone Button (Mimicking Attachment 2) */}
      <div className="absolute -left-14 bottom-1 p-3 rounded-full bg-white border morandi-border shadow-sm text-gray-400 hover:morandi-orange hover:morandi-border transition-all cursor-pointer hidden sm:flex">
        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
        </svg>
      </div>

      <div className="flex flex-col bg-white border morandi-border rounded-3xl shadow-xl overflow-hidden focus-within:ring-2 focus-within:ring-orange-100 transition-all">
        <div className="relative flex items-end p-2 px-4">
          <textarea
            ref={textareaRef}
            rows={1}
            value={text}
            onChange={(e) => setText(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="刚才会议中提到关于本季度预算增加15%的决策，请帮我记入纪要。"
            className="w-full bg-transparent border-none focus:ring-0 py-3 text-gray-700 text-sm placeholder:text-gray-300 resize-none min-h-[44px]"
            disabled={disabled}
          />

          <button
            onClick={handleSubmit}
            disabled={disabled || !text.trim()}
            className={`
              mb-1.5 p-2 rounded-xl transition-all
              ${text.trim() && !disabled 
                ? 'morandi-orange-bg text-white shadow-md' 
                : 'bg-gray-100 text-gray-300'
              }
            `}
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 5l7 7-7 7M5 5l7 7-7 7" />
            </svg>
          </button>

          {/* Warning Icon - Similar to Attachment 2 */}
          <div className="absolute right-12 bottom-3 p-1 rounded-lg morandi-orange-light text-[#e6a07c] cursor-pointer hover:bg-orange-100 transition-colors">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
            </svg>
          </div>
        </div>
      </div>

      {/* Footer Text */}
      <div className="mt-3 text-center text-[10px] text-gray-300 tracking-wide uppercase">
        AI-Powered | Morandi Design System v2.0
      </div>
    </div>
  );
};

