            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
            </svg>
         </button>
      </div>

      <div className="bg-white border morandi-border rounded-[2rem] shadow-[0_12px_40px_-12px_rgba(198,139,107,0.18)] overflow-hidden focus-within:ring-2 focus-within:ring-orange-50 transition-all">
        <div className="flex items-end p-2 sm:p-3 px-6">
          <textarea
            ref={textareaRef}
            rows={1}
            value={text}
            onChange={(e) => setText(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="请输入您的问题..."
            className="flex-1 bg-transparent border-none focus:ring-0 py-3 text-gray-700 text-sm placeholder:text-gray-300 resize-none min-h-[44px]"
            disabled={disabled}
          />

          <div className="flex items-center space-x-2 mb-1">
             <button
                onClick={handleSubmit}
                disabled={disabled || !text.trim()}
                className={`
                  p-3 rounded-2xl transition-all
                  ${text.trim() && !disabled 
                    ? 'morandi-orange-bg text-white shadow-lg shadow-orange-glow' 
                    : 'bg-gray-50 text-gray-200'
                  }
                `}
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M5 12h14M12 5l7 7-7 7" />
                </svg>
              </button>
          </div>
        </div>
      </div>

      {/* Disclaimer / Hints */}
      <div className="mt-3 flex items-center justify-center space-x-4 text-[10px] text-gray-300 font-medium tracking-widest uppercase">
        <span>Warm Intelligence</span>
