import React, { useState, useRef, useEffect } from 'react';

interface MessageInputProps {
  onSend: (text: string) => void;
  disabled?: boolean;
}

export const MessageInput: React.FC<MessageInputProps> = ({ onSend, disabled }) => {
  const [text, setText] = useState('');
  const [attachedFile, setAttachedFile] = useState<File | null>(null);
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = `${Math.min(textareaRef.current.scrollHeight, 150)}px`;
    }
  }, [text]);

  const handleSubmit = (e?: React.FormEvent) => {
    e?.preventDefault();
    if ((text.trim() || attachedFile) && !disabled) {
      // 这里的逻辑可以根据实际后端接口调整，目前先透传文字
      // 如果有文件，通常会在文字后加上文件提示
      const messageText = attachedFile 
        ? `${text.trim()} [附件: ${attachedFile.name}]`
        : text.trim();

      onSend(messageText);
      setText('');
      setAttachedFile(null);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSubmit();
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setAttachedFile(file);
    }
    // Reset input to allow selecting the same file again if needed
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const removeFile = () => {
    setAttachedFile(null);
  };

  const triggerFileUpload = () => {
    fileInputRef.current?.click();
  };

  return (
    <div className="relative group max-w-4xl mx-auto w-full">
      {/* Hidden File Input */}
      <input 
        type="file" 
        ref={fileInputRef} 
        className="hidden" 
        onChange={handleFileChange}
      />

      {/* Decorative Micro Button Area (LHS) */}
      <div className="absolute -left-16 bottom-3 flex flex-col items-center space-y-3 hidden sm:flex">
         <button 
           onClick={triggerFileUpload}
           title="上传附件"
           className="p-3 bg-white border morandi-border rounded-full text-gray-400 hover:morandi-orange hover:shadow-orange-glow transition-all"
         >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" />
            </svg>
         </button>
         <button className="p-3 bg-white border morandi-border rounded-full text-gray-400 hover:morandi-orange hover:shadow-orange-glow transition-all">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
            </svg>
         </button>
      </div>

      <div className="bg-white border morandi-border rounded-[2rem] shadow-[0_12px_40px_-12px_rgba(198,139,107,0.18)] overflow-hidden focus-within:ring-2 focus-within:ring-orange-50 transition-all flex flex-col">

        {/* Attachment Preview Area */}
